import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Select, StatusBadge, Pagination, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { gtService } from '../../../services/gt/gtService';
import type { CostSheetDto, WipBalanceDto } from '../../../services/gt/models';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { giaThanhPageLabels as L } from '../../../constants/giaThanhPageLabels';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const TEST_ID = 'erp-gia-thanh';
const PAGE_SIZE = 20;

const STATUS_OPTIONS = [
  { value: '', label: L.list.statusAll },
  { value: 'Draft', label: L.list.statusDraft },
  { value: 'Calculated', label: L.list.statusCalculated },
  { value: 'Approved', label: L.list.statusApproved },
  { value: 'Posted', label: L.list.statusPosted },
];

const GiaThanhListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [page, setPage] = useState(1);
  const [status, setStatus] = useState('');
  const [items, setItems] = useState<CostSheetDto[]>([]);
  const [wipRows, setWipRows] = useState<WipBalanceDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    Promise.all([
      gtService.getCostSheets({ month: Number(month), year: Number(year), status: status || undefined, page, pageSize: PAGE_SIZE }),
      gtService.getWipBalance(Number(month), Number(year)),
    ])
      .then(([res, wip]) => {
        setItems(res.items);
        setTotalCount(res.totalCount);
        setWipRows(wip);
      })
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, L.list.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [month, year, status, page, dispatch]);

  const wipOpening = wipRows.reduce((sum, row) => sum + row.openingAmount, 0);
  const wipClosing = wipRows.reduce((sum, row) => sum + row.closingAmount, 0);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) handleLoad(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [handleLoad]);

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-industry" /> {L.list.title}</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select value={month} onChange={e => { setMonth(e.target.value); setPage(1); }} options={MONTH_OPTIONS} data-testid={`${TEST_ID}-month`} />
        <Select value={year} onChange={e => { setYear(e.target.value); setPage(1); }} options={yearOptions()} data-testid={`${TEST_ID}-year`} />
        <Select value={status} onChange={e => { setStatus(e.target.value); setPage(1); }} options={STATUS_OPTIONS} data-testid={`${TEST_ID}-status`} />
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleLoad} onRefresh={handleLoad} showSearch={false} />
      </div>
      <div className={erp.summaryBar} data-testid={`${TEST_ID}-wip-summary`}>
        <div className={erp.summaryItem}><label className={erp.label}>{L.list.wipOpening}</label><strong>{formatVnd(wipOpening)}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>{L.list.wipClosing}</label><strong>{formatVnd(wipClosing)}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>{L.list.wipOrderCount}</label><strong>{wipRows.length}</strong></div>
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>{L.list.loading}</div> : items.length === 0 ? <div className={erp.empty}>{L.list.empty}</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th>{L.list.colCode}</th>
                  <th>{L.list.colProduct}</th>
                  <th className={erp.colRight}>{L.detail.actualQty}</th>
                  <th className={erp.colRight}>{L.list.colTotal}</th>
                  <th className={erp.colRight}>{L.list.colUnitCost}</th>
                  <th>{L.list.colStatus}</th>
                </tr>
              </thead>
              <tbody>{items.map(r => (
                <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                  <td><button type="button" className={erp.codeLink} onClick={() => navigate(`/gt/gia-thanh/${r.id}`)}><code>{r.code}</code></button></td>
                  <td>{r.productName ?? r.productCode}</td>
                  <td className={erp.colRight}>{r.actualQty}</td>
                  <td className={erp.colRight}>{formatVnd(r.totalCost)}</td>
                  <td className={erp.colRight}>{formatVnd(r.unitCost)}</td>
                  <td><StatusBadge status={r.status} /></td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
        {totalCount > 0 && (
          <div className={erp.paginationRow}>
            <Pagination currentPage={page} totalPages={Math.ceil(totalCount / PAGE_SIZE)} totalCount={totalCount} pageSize={PAGE_SIZE} onPageChange={setPage} />
          </div>
        )}
      </div>
    </div>
  );
};

export default GiaThanhListPage;
